const top = $input.first().json || {};
const body = top.body || top;
const resource = (body && body.resource) || top.resource || {};
const eventData = (body && body.eventData) || top.eventData || {};
const dataset_id = resource.defaultDatasetId || body.defaultDatasetId || top.defaultDatasetId || '';
const run_id = resource.id || body.run_id || eventData.actorRunId || '';
const task_id = eventData.actorTaskId || body.task_id || top['X-Apify-Task-Id'] || '';
const tenant_id = body.tenant_id || top.tenant_id || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const feature_id = body.feature_id || top.feature_id || '';
return [{ json: { dataset_id, run_id, task_id, tenant_id, feature_id, body, resource, eventData } }];

// FEAT-024 Recruitment Scam classifier
const items = $input.all();
const ev = $('Webhook').item.json.body || {};
const headers = ev.headers || {};
const tenantId = headers['x-tenant-id'] || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const taskId = ev.eventData?.actorTaskId || null;
const runId = ev.resource?.id || null;
const datasetId = ev.resource?.defaultDatasetId || null;

const OFFICIAL = ['CreditAccess Grameen Limited', 'Madura Micro Finance', 'MMFL'];
const FEE_RE  = /(processing|joining|training|registration)\s+fee|deposit|advance/i;
const PII_RE  = /\bPAN\b|\bAadhaar\b|\bAadhar\b/i;
const BRAND_RE = /CreditAccess|Grameen Koota|CA Grameen|Madura/i;

function platformFromSource(j) {
  const s = (j.source || j.platform || j.url || '').toLowerCase();
  if (s.includes('linkedin')) return 'apify:linkedin';
  if (s.includes('indeed'))   return 'apify:indeed';
  if (s.includes('glassdoor')) return 'apify:glassdoor';
  return 'apify:naukri';
}

const rows = [];
for (const itm of items) {
  const j = itm.json || {};
  const employer = j.employer || j.companyName || j.company || '';
  if (OFFICIAL.includes(employer)) continue;
  const desc = (j.description || j.jobDescription || '').toString();
  const recruiter = j.recruiter || j.recruiterName || j.postedBy || '';

  const red_flags = [];
  if (FEE_RE.test(desc)) red_flags.push('asks_processing_fee');
  if (PII_RE.test(desc)) red_flags.push('asks_pii_upfront');
  if (!recruiter || /HR|recruiter|admin/i.test(recruiter)) red_flags.push('unverified_recruiter');

  let severity = 'Moderate';
  if (red_flags.includes('asks_processing_fee') || red_flags.includes('asks_pii_upfront')) {
    severity = 'Critical';
  } else if (red_flags.length === 1 && red_flags[0] === 'unverified_recruiter' && BRAND_RE.test(desc + employer)) {
    severity = 'Substantial';
  }

  const confidence = severity === 'Critical' ? 0.9 : severity === 'Substantial' ? 0.7 : 0.5;
  const action = severity === 'Critical' ? 'takedown' : 'monitor';
  const url = j.url || j.applyUrl || j.jobUrl || '';
  const itemId = j.id || j.jobId || url;

  rows.push({
    tenant_id: tenantId,
    apify_task_id: taskId,
    apify_run_id: runId,
    apify_dataset_id: datasetId,
    feature_id: 'FEAT-024',
    source: platformFromSource(j),
    kind: 'job_scam',
    fraud_pattern: 'job_scam',
    severity,
    confidence,
    item_id: itemId,
    url_or_value: url || itemId,
    evidence: {
      platform: j.source || j.platform || null,
      job_title: j.title || j.jobTitle || null,
      employer,
      recruiter,
      salary: j.salary || j.salaryRange || null,
      location: j.location || j.city || null,
      posted_at: j.postedAt || j.postingDate || null,
      description_excerpt: desc.slice(0, 250),
      red_flags,
      application_url: j.applyUrl || null,
    },
    language_detected: j.language || null,
    timestamp_source: j.postedAt || j.postingDate || null,
    ai_filtered: false,
    ai_reason: `Red flags: ${red_flags.join(', ') || 'none'}`,
    recommended_action: action,
  });
}
return [{ json: { rows, count: rows.length } }];
